import React from "react";
import Navbar from "../components/Navbar";
import styled from "styled-components";
import {Link} from "react-router-dom";

const Container = styled.div`
    width: 100%;
    height: 92vh;
    background-color: #071330;
`;

const Wrapper = styled.div`
    height: 100%;
    display: flex;
    flex-direction: column;
`;


const Info = styled.h2`
    color: white;
`;

const Home = () => {
    return (
        <div>
            <Navbar/>
            <Container>
                <Wrapper>
                    <Info>Hi, I'm Joel Harawa, a senior at New York University studying Computer Science.</Info>
                    <Info>My main interests are web development and mobile app development.</Info>
                    <Info>Here are my Programming Languages (from strongest to weakest).</Info>
                </Wrapper>
            </Container>
        </div>
    );
}

export default Home;
